import { defineAxisId } from './utils/define-axis-id.js';
import type { ChartUnit } from '../../core/types/chart-unit.js';
import {
  isDynamicNumeric,
  isDynamicNumericRange,
  isStatic,
  isStaticRange,
} from '../../core/types/type-guards.js';
import type { HistogramThresholdsConfig } from '../../histogram/types/histogram-props.js';
import type { XYChartThresholdIndicatorProps } from '../../xy-chart/types/xy-chart-props.js';

const X_AXIS_ID = 'x-axis';

function buildPositionToAxisIdMap(units: ChartUnit[]): Record<string, string> {
  if (units.length <= 1) {
    const axisId = units.length === 1 ? defineAxisId(units[0]) : '';
    return { left: axisId, right: axisId };
  }

  const map: Record<string, string> = {};
  units.forEach((unit, index) => {
    const position = index % 2 === 0 ? 'left' : 'right';
    if (!(position in map)) {
      map[position] = defineAxisId(unit);
    }
  });

  return map;
}

export function mapHistogramThresholdsToXY(
  thresholds: HistogramThresholdsConfig | undefined,
  units: ChartUnit[],
): XYChartThresholdIndicatorProps[] {
  if (!thresholds) {
    return [];
  }

  const positionToAxisId = buildPositionToAxisIdMap(units);
  // `config.thresholds` is bucketed by axis position. Each item already
  // carries its `position`, so flattening both buckets restores the original
  // slot-shaped list this transformer reasons about.
  const flatThresholds = [
    ...(thresholds.leftThreshold ?? []),
    ...(thresholds.rightThreshold ?? []),
  ];

  return flatThresholds.reduce<XYChartThresholdIndicatorProps[]>(
    (result, threshold) => {
      const position = threshold.position ?? 'left';
      const yAxisId = positionToAxisId[position];

      if (!yAxisId) {
        return result;
      }

      const { data, color, label, strokeOnly } = threshold;

      if (isStatic(data)) {
        result.push({
          data: { y: data.value },
          color,
          label,
          strokeOnly,
          yAxisId,
        });
      } else if (isStaticRange(data)) {
        result.push({
          data: { yMin: data.min, yMax: data.max },
          color,
          label,
          strokeOnly,
          yAxisId,
        });
      } else if (isDynamicNumeric(data)) {
        result.push({
          data: data.map((d) => ({ y: d.value, x: d.point })),
          color,
          label,
          strokeOnly,
          yAxisId,
          xAxisId: X_AXIS_ID,
        });
      } else if (isDynamicNumericRange(data)) {
        result.push({
          data: data.map((d) => ({ yMin: d.min, yMax: d.max, x: d.point })),
          color,
          label,
          strokeOnly,
          yAxisId,
          xAxisId: X_AXIS_ID,
        });
      }

      return result;
    },
    [],
  );
}
